"""
mkt-original layer: Ezekiel 23-25
93 verses: ch23 (49) Oholah/Oholibah allegory, ch24 (27) cooking-pot + wife's death, ch25 (17) oracles against nations.
"""

import json, pathlib

ROOT = pathlib.Path(__file__).parent.parent

def load_comm(layer, book):
    p = ROOT / "data" / "commentary" / f"mkt-{layer}" / f"{book}.json"
    return json.loads(p.read_text()) if p.exists() else {}

def save_comm(layer, book, data):
    p = ROOT / "data" / "commentary" / f"mkt-{layer}" / f"{book}.json"
    p.parent.mkdir(parents=True, exist_ok=True)
    p.write_text(json.dumps(data, ensure_ascii=False, indent=None))
    print(f"  wrote {p.relative_to(ROOT)}")

def merge_comm(existing, new_data):
    for ch, verses in new_data.items():
        if ch not in existing:
            existing[ch] = {}
        for v, html in verses.items():
            if v not in existing[ch]:
                existing[ch][v] = html

EZEKIEL_ORIGINAL = {
  "23": {
    "1": "<p>The divine word-reception formula <strong>vayehi devar-YHWH elai lemor</strong> (<em>wayĕhî dĕbar-Yhwh ʾēlay lēmōr</em>), &#8220;the word of YHWH came to me saying,&#8221; opens the extended allegory. The formula is Ezekiel's signature marker of prophetic authority; it occurs over ninety times in the book, establishing each oracle's divine origin.</p>",
    "2": "<p><strong>ben-adam shtei nashim bnot em achat hayu</strong> (<em>ben-ʾādām štê nāšîm bĕnôt ʾēm ʾaḥat hāyû</em>): &#8220;Son of man, two women, daughters of one mother.&#8221; The allegory opens by establishing the shared origin of the two sisters. <em>Ben-adam</em> (son of man) is Ezekiel's distinctive address, occurring 93 times in the book — it simultaneously emphasizes human creaturely status before the divine glory and authorizes the prophet as YHWH's representative spokesman.</p>",
    "3": "<p><strong>vatiznenah bemitsrayim bineurehem zanu sham mudeku shadeyhen ushad almunotehem innu</strong> (<em>wattiznenâ bĕmiṣrayim binʿûrêhen zānû šām mudĕkû šĕdêhen ûšĕd ʿalmûnôtêhen ʿinnû</em>): <em>Zanah</em> (זָנָה, to prostitute/commit harlotry) is the governing verb of the entire chapter; it appears over 20 times. The chapter uses the most explicit sexual language in the OT not for titillation but for theological shock — to convey the magnitude of covenant betrayal that idolatry and foreign political alliances represent. The Egypt-origin of the whoredom (v. 3, 8, 19, 27) establishes that Israel's covenant-disloyalty is not an aberration but a pattern rooted in pre-Sinai bondage.</p>",
    "4": "<p><strong>Oholah hagdolah ve-Oholibah achoteha vatihyena li vateldna banim uvanot veshmotehem Shomron Oholah virushalayim Oholibah</strong> (<em>ʾŎhŏlāh haggĕdôlāh wĕ-ʾŎhŏlîbāh ʾăḥôtāh</em>): The names are themselves theological judgments. <strong>Oholah</strong> (ʾŏhŏlāh, &#8220;her own tent&#8221; or &#8220;tent of her own making&#8221;) = Samaria/northern kingdom: she built her own worship-center (Jeroboam's golden calves) rather than worshiping at YHWH's tent. <strong>Oholibah</strong> (ʾŏhŏlîbāh, &#8220;my tent is in her&#8221;) = Jerusalem/southern kingdom: YHWH's presence dwelt in her via the temple — making her betrayal all the more inexcusable. The name distinction encodes the entire theological verdict: Samaria invented her own worship; Jerusalem had the real thing and abandoned it.</p>",
    "5": "<p><strong>vatizna Oholah tachat vateehav el-asher hashorim shekheney aliyah Ashur</strong> (<em>wattizne ʾŎhŏlāh taḥtay wattĕʾehab ʾel-ʾăšer šĕkēnêhā ʾaššûr</em>): <em>Tachat</em> (under me, while belonging to me) — the betrayal is intensified by the covenant bond: she played the harlot while still YHWH's. The Assyrian alliance is the referent: Samaria's political vassalage to Assyria (2 Kings 17) is read as covenant adultery. The prophets consistently interpret foreign political alliances as acts of whoredom — seeking security from human powers rather than from YHWH is a theological act of faithlessness.</p>",
    "6": "<p><strong>levushey techelet pahot useganim bachuri chemah kulam parashim rokevey susim</strong> (<em>lĕbûšê tĕkēlet pāḥôt ûsĕgānîm baḥûrê ḥemdā kullām pārāšîm rōkĕbê sûsîm</em>): <em>Techelet</em> (תְּכֵלֶת, blue/violet dye) is the color of Assyrian official garments. The vividness of the description — handsome young men, mounted on horses, clothed in prestigious blue — conveys the seductive appeal of imperial power. Israel was drawn to the visible glory of foreign empires. The same blue is the color of the tabernacle coverings and the priestly garments; by using this color for the Assyrian warriors, YHWH indicates that what Israel sought from Assyria (glory, power, protection) she already possessed in him.</p>",
    "7": "<p><strong>vatiten znuteha lahem mivchar bney Ashur kol uvechol asher ahavah betamey gillulehem nitma</strong> (<em>wattittēn zĕnûtêhā ʿălêhem mibḥar bĕnê ʾaššûr kol wĕbĕkol ʾăšer āhĕbâ bĕkol-gillûlêhem niṭmāʾ</em>): <strong>Gillulim</strong> (גִּלּוּלִים, idols) is Ezekiel's characteristic pejorative term for idols — likely derived from <em>gelel</em> (dung pellets) or <em>gal</em> (log/block). It appears 39 times in Ezekiel alone (out of 48 OT occurrences), more than in any other book. The scatological contempt of the term is deliberate: Ezekiel's prophetic strategy is to defamiliarize the idols, stripping them of their glamour by naming them excrement.</p>",
    "8": "<p><strong>vezet znuteha lo azva me-al mitsrayim ki otah shachevu bineureha vehem daku et-shad almunoteha vayishpeku et-taznutehem aliyah</strong> (<em>wĕʾet zĕnûtêhā mimiṣrayim lōʾ ʿāzābāh</em>): The Egypt-connection is theologically central: the whoredom patterns were learned in slavery and never abandoned. Ezekiel's reading inverts the Exodus narrative — rather than Israel being freed from Egypt's influence at the Red Sea, Egypt's spiritual contamination persisted. This is his radical diagnosis: Israel did not bring only slaves out of Egypt; they brought idolatrous habits that would corrupt them for generations (cf. Ezek 20:7-8: even in Egypt they did not forsake the idols of Egypt).</p>",
    "9": "<p><strong>lachen natatiyah beyad meahaveyha beyad bney Ashur asher ahavah aliyehem</strong> (<em>lākēn nĕtattîhā bĕyad mĕʾahăbêhā bĕyad bĕnê ʾaššûr ʾăšer āhăbāh</em>): <em>Natan beyad</em> (gave into the hand) is the covenant-abandonment formula — YHWH withdraws his protection and delivers into the hands of the one pursued. The theological logic is stark: Oholah/Samaria ran after Assyria for protection; YHWH gives her over to Assyria as her destroyer. The very partner she sought for security becomes the instrument of her judgment. This is the pattern Paul identifies in Romans 1:24-28: God gave them over to what they desired.</p>",
    "10": "<p><strong>hem gallu ervata beneyha uvnoteyha laqachu ve-otah bacherev haragu vatehi shem lannashim veshfatim asu vah</strong> (<em>hēmmāh gillû ʿerwātāh bānêhā ûbĕnôtêhā lāqāḥû wĕʾôtāh baḥereb hārāgû</em>): <em>Gillah ervah</em> (uncovered nakedness) is the covenant-shame enacted in judgment — the reversal of YHWH's covering in Ezek 16:8. The Assyrian deportation of Samaria (722 BCE) is this &#8220;execution of judgment.&#8221; The note &#8220;she became an object of infamy among women&#8221; (<em>shem lenashim</em>) uses the female-shaming language of ancient Near Eastern culture — her dishonor is public and complete.</p>",
    "11": "<p><strong>vatere achoteha Oholibah vatashchet tahavata mimeha veet-znuteyha mimiznut achoteha</strong> (<em>wattarĕʾ ʾăḥôtāh ʾŎhŏlîbāh wattašḥēt taʾăwātāh mimmennâ wĕʾet-zĕnûtêhā mizzĕnût ʾăḥôtāh</em>): <em>Vatashchet</em> (more corrupt) — Jerusalem's sin is worse than Samaria's because she witnessed Samaria's punishment and still persisted. The principle is escalation: knowing the outcome of another's covenant-breach and continuing anyway is more culpable than ignorance. This is the logic behind Jesus's &#8220;more tolerable for Sodom&#8221; pronouncements (Matt 10:15; 11:23-24).</p>",
    "12": "<p><strong>el-bney Ashur ahavah pahot useganim qerovim levushey mikhlol parashim rokevey susim bachure chemad kulam</strong> (<em>ʾel-bĕnê ʾaššûr āhăbāh pāḥôt ûsĕgānîm qĕrôbîm lĕbûšê miklōl</em>): The description of Oholibah's infatuation with Assyrian officials precisely mirrors verses 5-6 about Oholah — showing that both sisters fell for the same visual spectacle. The repetition is artistic: Oholibah saw what happened to Oholah and was seduced by the same images anyway.</p>",
    "13": "<p><strong>vaere ki nitma derekh echad lishtehem</strong> (<em>wāʾerĕʾ kî niṭmāʾ dereḵ ʾeḥād lišĕtêhem</em>): &#8220;I saw that she was defiled — both had taken the same way.&#8221; YHWH sees (<em>vayare</em>) and pronounces the verdict: <em>tamei</em> (defiled/unclean) — the technical cultic-holiness term applied to spiritual and moral corruption. <em>Derekh echad</em> (one way/path) — they converge in the same trajectory of apostasy. The watchman-YHWH sees what the nation refuses to see about itself.</p>",
    "14": "<p><strong>vatosed el-znuteyha vatere anshey mechukeh al-haqqir tsalmey Kasdim mechukke veshashar</strong> (<em>wattôsep ʾel-zĕnûtêhā wattarĕʾ anšê mĕḥuqqeh ʿal-haqqîr ṣalmê kaśdîm mĕḥuqqê bassāšar</em>): <em>Tsalmey Kasdim</em> (images/portraits of Chaldeans) — painted murals of Babylonian warriors. <em>Shashar</em> (שָׁשַׁר, red ochre/vermilion) is the pigment used for decorative paintings. The sight of painted warriors triggers desire — a profound observation about the psychology of idolatry: the image (tselem) inflames the imagination. This is also a wordplay on the divine <em>tselem</em> (image/likeness) in Gen 1:26-27 — humanity, made in God's image, loses itself chasing counterfeit images.</p>",
    "15": "<p><strong>azone ezor bematnehem saruchey tifara beresheyhem mareh shalishim kulam demet bney Bavel Kasdim erets moladatam</strong> (<em>ʾăzûnê ʾēzôr bĕmotnêhem sĕrûḥê ṭifārâ bĕrāʾšêhem marʾēh šālîšîm kullām dĕmût bĕnê-bābel kaśdîm ʾereṣ môlādātām</em>): The attention to fashion detail — belted waists, elaborate headdresses, officer-like appearance — is part of Ezekiel's satirical strategy. What Jerusalem found glamorous (Babylonian military fashion) is described with a cataloguer's precision that simultaneously deflates its mystique. Babylon is fully named here: <em>eretz moladatam</em> (the land of their birth) — this is not mysterious or divine; it is merely human geography.</p>",
    "16": "<p><strong>vatahav aliyehem lemarat eneyha vatishlach malakhim aliyehem Kasdima</strong> (<em>wattĕʾehab ʾălêhem lĕmirʾēh ʿênêhā wattišlaḥ malʾākîm ʾălêhem kaśdîmāh</em>): <em>Lemarat eneyha</em> (at the sight of her eyes) — the immediacy of the desire, triggered by sight alone. <em>Vatishlach malakhim</em> (sent messengers to them) — the active pursuit reverses the expected gender dynamic. Jerusalem does not wait to be courted; she initiates. The theological point: covenant-breaking is not passive drift but active, deliberate pursuit of what YHWH has prohibited.</p>",
    "17": "<p><strong>vayavo-u eliyah bney Bavel lemishtav dodim vayetamu-u otah betaznuteham vatatema bam vataqats naphsha mehem</strong> (<em>wayyābōʾû ʾēlêhā bĕnê-bābel lĕmiškaḇ dōdîm wayyĕṭammĕʾû ʾôtāh bĕtaznûtām</em>): <em>Mishkab dodim</em> (bed of love/beloved's bed) — the language inverts the covenantal &#8220;bed&#8221; of faithful union. The same root (<em>dod</em>) is used in the Song of Songs for legitimate conjugal love; here it is the language of covenant betrayal. The clause &#8220;her heart turned away from them&#8221; (<em>vataqats naphsha mehem</em>) is psychologically acute: the infatuation cools after the act, leaving only defilement.</p>",
    "18": "<p><strong>vategel znuteyha vetegal et-ervatah vataqats naphshi mealiyah kasher naqtsah naphshi me-al achoteha</strong> (<em>wattĕgal zĕnûtêhā wattĕgal ʾet-ʿerwātāh wattāqoṣ naphšî mēʿālêhā kaʾăšer nāqŏṣâ naphšî mēʿal ʾăḥôtāh</em>): YHWH's response is expressed in anthropomorphic emotional language: <em>vataqats naphshi</em> (my soul/being turned in disgust). The same verb used for Jerusalem's own disgust at Babylon (v. 17) is now applied to YHWH's turning from Jerusalem — a precise reversal. The God who is repelled by covenant betrayal experiences the same revulsion the unfaithful wife felt for her paramour.</p>",
    "19": "<p><strong>vatarbe et-znuteyha lizkor et-yemey neureha asher zantah be-erets mitsrayim</strong> (<em>wattarbeh ʾet-zĕnûtêhā lizkōr ʾet-yĕmê nĕʿûrêhā ʾăšer zānĕtāh bĕʾereṣ miṣrāyim</em>): <em>Lizkor</em> (to remember/recall) — memory as spiritual danger. Ezekiel diagnoses the spiritual disease as nostalgic memory of Egypt: the very act of remembering the past generates renewed desire for what was. This is the psychology of recidivism — dwelling on former sins reinflames them. The spiritual discipline implied is the opposite: forgetting what lies behind (Phil 3:13) and not returning to the vomit (Prov 26:11; 2 Pet 2:22).</p>",
    "20": "<p><strong>vatahev al-pilagsheyhem asher besar chamorim besaram uvezirmat susim zirmatam</strong> (<em>wattĕʾehab ʿal-pîlgĕšêhem ʾăšer bĕśar ḥămôrîm bĕśārām ûzirmat sûsîm zimmātām</em>): <em>Zirmah</em> (זִרְמָה, seminal emission) and <em>basar</em> (flesh) — Ezekiel uses the most anatomically explicit language in the OT to describe Jerusalem's spiritual condition. The graphic comparison to donkeys and horses is a deliberate desecration of the romantic narrative: what Jerusalem calls love is mere animal lust without covenant meaning. The theological purpose is total defamiliarization — to make the reader see foreign political/religious alliances as Ezekiel (and YHWH) see them: as debasement, not glamour.</p>",
    "21": "<p><strong>vatiphqedi et-zimmat neureykhi badaqdeq shadayikh lemaan dade mitsrayim</strong> (<em>wattipqĕdî ʾet-zimmat nĕʿûrāyik bĕdadqēq šādayik lĕmaʿan dĕdê miṣrāyim</em>): <em>Vatiphqedi</em> (you called to mind/remembered — Hiphil) — the deliberate act of remembering compounds the guilt. <em>Zimmat neureykhi</em> (lewdness of your youth) — the sin of origins is being consciously revived. The Egypt-sexual imagery (breasts pressed, youthful nipples) creates a theological scandal: the founding redemptive narrative of the Exodus is contaminated at its source by Israel's spiritual harlotry.</p>",
    "22": "<p><strong>lachen Oholibah ko amar Adonai YHWH hineni meir et-meahaveykhi alaykhi me-asher naqa naphsheykhi mehem veheveti otam alaykhi miqqol saviv</strong> (<em>lākēn ʾŎhŏlîbāh kōh ʾāmar ʾădōnāy Yhwh hinnênî mēʿîr ʾet-mĕʾahăbayik ʿālayik</em>): <em>Hineni meir</em> (I am raising up) — the divine first-person announcement of judgment. The ironic justice: YHWH will use the very partners Jerusalem pursued (Babylonians, Assyrians) as the instruments of her punishment. The lovers become the executioners. This is the classic prophetic judgment-pattern: the means of covenant-breaking become the means of covenant-curse.</p>",
    "23": "<p><strong>Bavel vekhol Kasdim Pekod veShoa veQoa vekhol bney Ashur itam bachure chemad kulam pahot useganim sarshim veqruim kulam parashim</strong> (<em>bābel wĕkhol kaśdîm pĕqōd wĕšôaʿ wĕqôaʿ wĕkol bĕnê ʾaššûr</em>): The catalog of nations — <strong>Pekod</strong>, <strong>Shoa</strong>, and <strong>Koa</strong> — are Aramean/Babylonian tribal confederates known from Akkadian records. The specificity of the list is polemical: these are real historical peoples, not mythological forces. YHWH's judgment comes through concrete geopolitical realities, not mystical interventions.</p>",
    "24": "<p><strong>uvau alaykhi rechev karkar vegalgal uveqahal amim tsina vemagen veqova yassimu alaykhi saviv venatati lifneihem mishpat ushefatu otakh bemishpeteyhem</strong> (<em>ûbāʾû ʿālayik reḵeb karkār wĕgalgal ûbeqahal ʿammîm</em>): <em>Mishpat</em> (judgment, ordinances) — &#8220;they will judge you by their own ordinances&#8221; is a chilling phrase: the Babylonian legal system, not the Torah, will be the instrument of Jerusalem's judgment. This is the covenantal irony: the nation that abandoned YHWH's <em>mishpat</em> will be judged by pagan <em>mishpat</em>. The loss of covenant-protection means vulnerability to foreign legal systems.</p>",
    "25": "<p><strong>venatati kinat bi veashu otakh bechema af veoznekh veoznekh yikratu vesheritek bacherev tipol beney uvnotekh yiqachu vacharitekh baesh tikle</strong> (<em>wĕnāṭattî qinʾātî bāk wĕʿāśû ʾôtāk bĕḥēmā</em>): <em>Qinah</em> (קִנְאָה, jealousy/zeal) — YHWH's jealousy is the covenant emotion of the marriage bond. The physical mutilation described (cutting off nose and ears) is attested in ancient Near Eastern punishment for adultery. The nose-ring and ear-rings were symbols of the covenant adorning (Ezek 16:11-12); their removal is the covenant-curse enacted on the body.</p>",
    "26": "<p><strong>hikhu begdeykhi velaqchu kley tipherteykhi</strong> (<em>hikkû bigdāyik wĕlāqĕḥû kĕlê tipʾarteykhi</em>): <em>Bigdayikh</em> (your garments) and <em>kley tipherteykhi</em> (your beautiful ornaments) — these are the garments and adornments YHWH gave Jerusalem in the covenant-marriage (Ezek 16:10-13): fine linen, silk, embroidered cloth, bracelets, necklace, nose-ring, earrings, crown. Their stripping reverses the covenant-clothing. Exile is unclothing — the removal of the divine gifts that marked covenant status.</p>",
    "27": "<p><strong>vehishabati zimmatekhi mimeykh veznut heveyt me-erets mitsrayim velo tise-i einayikh alayehem ulomitsrayim lo tizkeri-od</strong> (<em>wĕhišbattî zimmatēk mimmēk wĕzĕnût hûbāʾt mēʾereṣ miṣrāyim wĕlōʾ tiśśĕʾî ʿênayik ʾălêhem</em>): <em>Vehishabati zimmatekhi</em> (I will bring your lewdness to an end) — the judicial resolution formula. The prophecy points toward a post-judgment purification in which the Egypt-pattern that has dominated all of Israel's history will finally be broken. The &#8220;no longer looking toward Egypt&#8221; anticipates the new covenant transformation (Ezek 36:24-28) when YHWH himself enables what Israel could not accomplish through her own moral effort.</p>",
    "28": "<p><strong>ki ko amar Adonai YHWH hineni noten otach beyad sane-aykh beyad asher qatsa naphsheykh mehem</strong> (<em>kî kōh ʾāmar ʾădōnāy Yhwh hinnênî nōtēn ʾôtāk bĕyad śōnĕʾayik bĕyad ʾăšer qāṣâ naphšēk mēhem</em>): The divine messenger formula (<em>ko amar Adonai YHWH</em>) marks this as the authoritative royal decree. &#8220;Into the hand of those from whom your heart has turned&#8221; — the handing-over is precisely to the ones Jerusalem abandoned in disgust. The judgment is a divinely ordered inversion of desire: the ones rejected become the ones who dominate.</p>",
    "29": "<p><strong>veashu vekhi binah velachu yegiakhi vehenichu otakh eirom vearum venikla ervat znutaykhi vezimmatekh venaphutaykhi</strong> (<em>wĕʿāśû ʾôtāk bĕśinʾāh wĕlāqĕḥû kol yĕgîʿēk wĕhinnîḥû ʾôtāk ʿêrōm wĕʿeryāh</em>): <em>Einah</em> (hatred) — the lovers' hatred completes the trajectory: desire → defilement → disgust → hatred. The progression describes the dynamics of idolatrous attachment: the thing pursued with such intensity ultimately generates contempt in both directions. <em>Eirom vearum</em> (naked and bare) — the covenant-clothing stripped away, returning Jerusalem to the exposed infant state of Ezek 16:4.</p>",
    "30": "<p><strong>asitah eleh timaeti ki zint achrey hagoyim al gillulehem nitme-it</strong> (<em>ʿāśtāh ʾēlleh ʾittāk bĕzanôtēk ʾaḥărê haggôyim ʿal gillûlêhem niṭmēʾt</em>): <em>Titme-i</em> (you defiled yourself) — the reflexive form emphasizes personal agency. <em>Gillulim</em> again — the contamination of idolatry is not merely ritualistic but ontological; contact with &#8220;dung-pellets&#8221; makes one &#8220;dung.&#8221; The nations' idols are called <em>gillulim</em> precisely because Israel became like what she worshiped (Ps 115:8: &#8220;those who make them become like them&#8221;).</p>",
    "31": "<p><strong>bederekh achoteykhi halachti velaqachti kosah beyadeykh</strong> (<em>bĕdereḵ ʾăḥôtēk hālaket wĕnātatî kôsāh bĕyādēk</em>): <em>Kos achoteykhi</em> (your sister's cup) — the cup of judgment is a major prophetic image (Jer 25:15-17; Isa 51:17-23; Rev 14:10; 16:19). Walking in the way of Oholah/Samaria means inheriting Samaria's cup. The cup-image captures both the communal nature of judgment (a cup is passed around) and its intoxicating, destabilizing quality — judgment comes as a force that overwhelms self-control.</p>",
    "32": "<p><strong>ko amar Adonai YHWH kos achoteykhi tisht-i hammuqah veharehivah tehiyeh litshoq velalas harbe lehachil</strong> (<em>kōh ʾāmar ʾădōnāy Yhwh kôs ʾăḥôtēk tištî haʿamuqâ wĕhārĕḥābāh tihyeh liṣḥōq wĕlālaʿag harbēh lĕhāḵîl</em>): The cup of judgment is described as <em>amuqah verehivah</em> (deep and wide) — its capacity exceeds what can be drunk at once. The mockery (<em>tshoq velaalas</em>) that accompanies the drinking adds shame to suffering. In Revelation's eschatology (Rev 14:10; 16:19), the cup of God's wrath is the final consummation of this Ezekielian cup-of-judgment theme.</p>",
    "33": "<p><strong>shikkaron veyagon timale-i kos shomah ushemamah kos achoteykhi Shomron</strong> (<em>šikkārôn wĕyāgôn timmālĕʾî kôs šammāh ûšĕmāmāh kôs ʾăḥôtēk šōmĕrôn</em>): <em>Shikkaron</em> (שִׁכָּרוֹן, drunkenness) and <em>yagon</em> (יָגוֹן, grief/sorrow) — the cup produces both intoxication (loss of capacity for rational self-defense) and anguish. <em>Shomah ushemamah</em> (horror and desolation) — the cup is Samaria's own experience of 722 BCE. Jerusalem is about to drink what her sister drank.</p>",
    "34": "<p><strong>ushtit vematsit vecherasheyha tilchakhi veeth sadeykhi tinaqeri ki ani dibarti neum Adonai YHWH</strong> (<em>ûšātît wĕmāṣît wĕḥarāśêhā tillaḥăkî wĕʾet šādayik tĕnaqqērî kî ʾănî dibbartî nĕʾum ʾădōnāy Yhwh</em>): <em>Ushtit umatsit</em> (drink and drain it) — the cup must be completely emptied; there is no setting it down half-finished. The self-mutilation (gnawing the shards, tearing out the breasts) conveys the total self-destruction that comes when judgment runs its full course. The closing formula <em>neum Adonai YHWH</em> (declares the Lord GOD) is Ezekiel's divine-signature stamp: this is not poetic hyperbole but divine decree.</p>",
    "35": "<p><strong>lachen ko amar Adonai YHWH yaan shachacht oti vatashlikhiy achoreyikh et-guve vasgay zimmatekhi veznutekhi</strong> (<em>lākēn kōh ʾāmar ʾădōnāy Yhwh yaʿan šākaḥt ʾôtî wattašlîḵî ʾaḥărêk ʾet-gēwek</em>): <em>Shachacht oti</em> (you forgot me) — the covenant-breach is defined as forgetting. The opposite of faithful covenant-love is not hatred but forgetting — treating YHWH as irrelevant to daily political and religious life. <em>Vatashlikhiy achoreyikh</em> (cast behind your back) — the active dismissal of YHWH into irrelevance. This is the theological diagnosis beneath all the allegory: structural amnesia toward the covenant God.</p>",
    "36": "<p><strong>vayomer YHWH elai ben-adam hashpot hashpot et Oholah ve-et-Oholibah vehagid lahem et-toavoteyhem</strong> (<em>wayyōmer Yhwh ʾēlay ben-ʾādām hăšpôṭ hăšpōṭ ʾet-ʾŎhŏlāh wĕʾet-ʾŎhŏlîbāh wĕhaggēd lāhem ʾet-tôʿăbōtêhem</em>): <em>Hashpot hashpot</em> (will you judge / judge!) — the doubled imperative (infinitive absolute + finite verb) emphasizes the urgency and authority of the prophetic indictment. The prophet as judge (<em>shofet</em>) is acting in YHWH's court, presenting evidence. The declaration of <em>toavot</em> (abominations) is not personal vituperation but legal testimony before the divine tribunal.</p>",
    "37": "<p><strong>ki niefufah vi veyad dam lifneyhen ihe veet-gillulehem niefufah vatehayinah baney asher yeladu li heviru lahem baesh leakhela</strong> (<em>kî niʾăp̄û wĕyādê dāmîm lifnêhen ûbĕgillûlêhem niʾāp̄û wĕʾet-bĕnêhem ʾăšer yālĕdû-lî hiʿbîrû lāhem bāʾēš lĕʾāklâ</em>): <em>Niafufah vi</em> (they committed adultery with/against me) — adultery against YHWH and idolatry are synonymous. <strong>Heeviru baesh</strong> (pass through fire) is Molech worship — child sacrifice to the Ammonite deity. &#8220;Children they bore to me&#8221; — these children were covenant members, belonging to YHWH, sacrificed to idols. The covenantal crime intensifies: not their own lives but their children's lives are sacrificed to <em>gillulim</em>.</p>",
    "38": "<p><strong>od zot asu li timeu et-miqdashi vayom hahu veet-shabbetotay chilelu</strong> (<em>ʿôd zōʾt ʿāśû lî ṭimmĕʾû ʾet-miqdāšî bayyôm hahûʾ wĕʾet-šabbĕtôtay ḥillēlû</em>): <em>Timeu miqdashi</em> (defiled my sanctuary) — the sanctuary-defilement motif is central to Ezekiel's theology. The very space where YHWH's presence dwells becomes the site of abomination when covenant-people bring their defiled selves and objects into it. &#8220;On the same day&#8221; — the temple and Molech worship happening simultaneously, perhaps on the Sabbath itself, is the maximum possible sacrilege.</p>",
    "39": "<p><strong>ki veshochtam et-beneihem legilulehem vayavo-u el-miqdashi vayom hahu lechallelo vehine chen asu betokh beiti</strong> (<em>kî bĕšoḥăṭām ʾet-bĕnêhem lĕgillûlêhem wayyābōʾû ʾel-miqdāšî bayyôm hahûʾ lĕḥallĕlô</em>): The sequence — slaughter children for idols, then enter the sanctuary — reveals the complete collapse of the distinction between sacred and profane. The people move between Molech-worship and YHWH-worship as though both are equally valid religious options. Ezekiel's horror is theological: the sanctuary becomes complicit in the abomination when those who have just sacrificed children to idols enter it unrebuked.</p>",
    "40": "<p><strong>vaaf ki tishlechna el-anashim bai-im memarchaq asher malach shalach alayhem vehine bau asher rachatzta kachalt einayikh veatdiy adi</strong> (<em>wĕʾap̄ kî tišlaḥnâ ʾel-ʾănāšîm bāʾîm mimmereḥōq ʾăšer malʾāk šālaḥ ʾălêhem</em>): <em>Kachalt einayikh</em> (painted your eyes) — cosmetic eye-painting, widely practiced in the ancient Near East, was associated with seduction. The same verb (<em>puk</em>) is used for Jezebel's eye-painting before Jehu's arrival (2 Kings 9:30) and for the harlot's preparations (Prov 7:17). Jerusalem is the seducer who adorns herself to attract foreign nations — reversing the expected direction of political dependency.</p>",
    "41": "<p><strong>veyashavt al-mitat mechubad veshulchan arukh lefaneyha veqotereti veshemeni samta aleyha</strong> (<em>wĕyāšabt ʿal-miṭṭat mĕkubbād wĕšulḥān ʿārûk lĕpānêhā wĕqoṭartî ûšamnî śamtĕ ʿālêhā</em>): <em>Qotereti veshemeni</em> (my incense and my oil) — YHWH's covenant gifts (incense and oil designated for the tabernacle service) are placed on a table prepared for foreign guests. The sacred materials of YHWH-worship are repurposed for covenant-breaking hospitality. This is the logic of spiritual syncretism: taking what belongs to YHWH and putting it in service of other loyalties.</p>",
    "42": "<p><strong>veqol hamon shalem bo avel el-anashim merov adam muveim midbara vayitnu tsemidim al-yadeyhen vetiferet atarot al-rosheyhen</strong> (<em>weqôl hāmôn šālēw bāh wĕʾel-ʾănāšîm mērōb ʾādām mûbāʾîm midbārâ wayyittĕnû ṣemîdîm ʿal-yĕdêhen</em>): <em>Midbar</em> (wilderness) — the Sabeans come from the wilderness. The bracelets (<em>tsemidim</em>) and crowns (<em>atarot</em>) placed on these women by foreign guests are debased versions of the covenant adornments YHWH gave (Ezek 16:11-12). Foreign gifts replace divine gifts as markers of identity.</p>",
    "43": "<p><strong>vaomar lablah niufim ata yiznu znuteha vehi</strong> (<em>wāʾōmar lablāh nîʾupîm ʿattāh yizněnû zĕnûtêhā wĕhîʾ</em>): <em>Lablah niufim</em> (worn out/exhausted by adulteries) — YHWH's rhetorical question has bitter irony: will they still go to her? — even now, when she is worn out? The question implies the hopelessness of the situation: even the withered, exhausted idolater still attracts her idolatrous partners. Sin has its own momentum that persists beyond reason or dignity.</p>",
    "44": "<p><strong>ubau-u eleyha kasher yavo-u el-isha zonah ken bau el-Oholah ve-el-Oholibah nashim hazimot</strong> (<em>ûbāʾû ʾēlêhā kaʾăšer yābōʾû ʾel-ʾiššâ zônāh kēn bāʾû ʾel-ʾŎhŏlāh wĕʾel-ʾŎhŏlîbāh nāšîm hazzimmôt</em>): <em>Nashim hazimot</em> (lewd/scheming women) — <em>zimmah</em> (זִמָּה) means both lewdness and deliberate scheming. The term appears in Leviticus for the most serious sexual crimes. Both sisters are now formally named <em>zimmot</em> — a legal-theological verdict. The allegory arrives at its judicial climax: they are not merely flawed but categorically criminal by Torah standards.</p>",
    "45": "<p><strong>anashim tsadiqim hema yishpetu otam mishpat noaphot umishpat shofakhot dam ki noaphot henah vedam biyadeyhem</strong> (<em>ʾănāšîm ṣaddîqîm hēmmāh yišpĕṭû ʾôtām mišpaṭ nōʾăp̄ôt ûmišpaṭ šōp̄ĕkôt dām kî nōʾăp̄ôt hēnnâ wĕdām bĕyĕdêhen</em>): <em>Anshe tsadiqim</em> (righteous men) — the righteous community as co-judges reflects the covenant assembly's role in executing Torah-judgment. The dual charges are adultery (<em>niufim</em>) and bloodshed (<em>shofakhot dam</em>) — the two great covenant-crimes that defile the land (Num 35:33-34). Together they represent the collapse of the two great commandments: faithfulness to God (adultery against YHWH) and protection of human life (bloodshed).</p>",
    "46": "<p><strong>ki ko amar Adonai YHWH haaleh aleyhen qahal venaten otahan lerogzah velabaz</strong> (<em>kî kōh ʾāmar ʾădōnāy Yhwh haʿălēh ʾălêhen qāhāl wĕnātan ʾôtāhen lĕrāgzāh wĕlābaz</em>): <em>Qahal</em> (assembly/congregation) brought against them — the same word used for the covenant assembly of Israel (<em>qahal YHWH</em>) is now weaponized: the assembly assembles not for worship but for execution of judgment. The covenant community that should have been a worshiping congregation becomes instead the instrument of covenantal punishment.</p>",
    "47": "<p><strong>veragmu alayhen even qahal vebareh othan becharbot baneyhen uvnoteyhen yaharegu uvateyhenn beesh yisrofu</strong> (<em>wĕrāgĕmû ʾălêhen ʾeben qāhāl ûbāreʾ ʾôtāhen beḥarbôt</em>): <em>Ragam even</em> (stoning with stones) — the covenant penalty for adultery (Deut 22:21-24; John 8:5). Burning of houses compounds the judgment. The execution of the allegorical sisters is the prophetic coding of the Babylonian destruction: the armies are the assembly, the sword is the execution, the burning is the 586 BCE conflagration. The allegory provides the theological meaning for what would otherwise be mere military history.</p>",
    "48": "<p><strong>vehishabati zimma meen-haaretz veniyssiru kol-hanashim velo taasena kezimmatkhena</strong> (<em>wĕhišbattî zimmāh mēhāʾāreṣ wĕniwwasrû kol-hannāšîm wĕlōʾ taʿăśenāh kezimmatĕkennāh</em>): <em>Vehishabati zimma meen-haaretz</em> (I will bring lewdness to an end from the land) — the judgment has a restorative purpose: to remove the pattern of covenant betrayal from the land so that the land itself can be healed. <em>Veniyssiru kol-hanashim</em> (all women may be warned/instructed) — the allegory serves a pedagogical function for future generations: the account of Oholah and Oholibah is a warning, not merely a condemnation.</p>",
    "49": "<p><strong>venasenu zimmatkhena alaykhena vechet gilluleykhen tise-na vidu-aten ki ani Adonai YHWH</strong> (<em>wĕnāśʾû zimmatkennāh ʿălêkennāh wĕḥêṭ gillûlêkhen tiśśeʾnāh wîdaʿten kî ʾănî ʾădōnāy Yhwh</em>): <em>Nasenu zimmatkena alaykhena</em> (your lewdness returned upon you) — the covenant-curse principle of Leviticus 26 in operation: the sin comes back upon the sinner. <em>Yadatem ki ani Adonai YHWH</em> — the recognition formula that closes the oracle. The purpose of judgment is not mere punishment but knowledge: when the judgment falls, Israel will at last know who YHWH truly is — not the abstracted deity they treated as one option among many, but the sole sovereign LORD who keeps covenant and keeps judgment.</p>"
  },
  "24": {
    "1": "<p><strong>vayehi dvar-YHWH elai bishnat hateshiit bachodesh haasiri beahor lachodesh lemor</strong> (<em>wayhî dĕbar-Yhwh ʾēlay bišnat hattĕšîʿît baḥōdeš hāʿăśîrî bĕʾeḥād laḥōdeš lēmōr</em>): The precise date — ninth year, tenth month, tenth day — is one of Ezekiel's six exact dates (1:2; 8:1; 20:1; 24:1; 26:1; 29:1). This date corresponds to January 588 BCE and aligns with 2 Kings 25:1 and Jer 52:4: the day Nebuchadnezzar's siege of Jerusalem began. Ezekiel in Babylon receives the word on the exact day the siege begins in Jerusalem — a demonstration of prophetic foreknowledge and YHWH's sovereign coordination of events across 800 miles.</p>",
    "2": "<p><strong>ben-adam ketov lecha et-shem hayom et-etzem hayom hazeh samach melekh-Bavel el-Yerushalayim beetzem hayom hazeh</strong> (<em>ben-ʾādām kĕtōb lĕkā ʾet-šem hayyôm ʾet-ʾeṣem hayyôm hazzeh</em>): <em>Ketov lecha</em> (write down for yourself) — the command to record the date creates a prophetic document of synchrony. <em>Etzem hayom hazeh</em> (this very day / the bone of this day) — the word <em>etzem</em> (bone/substance) intensifies the present moment: this is not an approximate or symbolic date but the actual day of siege-commencement. The prophetic act of recording the date is itself a theological statement: YHWH knows the precise moment and has planned around it.</p>",
    "3": "<p><strong>umashol el-beit hameri mashal veamarta alayhem ko amar Adonai YHWH shefot hasir shefot vegam-yeqeh mavim aleyhu</strong> (<em>ûmšōl ʾel-bêt hammerî māšāl wĕʾāmartā ʾălêhem kōh ʾāmar ʾădōnāy Yhwh šĕpōṭ-hassîr šĕpōṭ</em>): <em>Mashal</em> (parable/allegory) — the parable of the cooking pot (<em>sir</em>) is YHWH's command to Ezekiel. <em>Beit hameri</em> (rebellious house) — this is Ezekiel's standard epithet for Israel (occurring in chs. 2-3, 12, 17, 24, 44). The pot-parable reverses the image the Jerusalem leaders were using as self-reassurance (Ezek 11:3: &#8220;this city is the pot and we are the meat&#8221; — meaning the pot protects the contents). Ezekiel accepts their metaphor but redefines it: yes, Jerusalem is a pot — but one filled with filth and scum, not a protective vessel.</p>",
    "4": "<p><strong>esof netacheha eliyah kol-netach tov yarekh vekhatef male atzamot mivchar</strong> (<em>ʾĕsōp̄ nĕtāḥêhā ʾēlêhā kol-nētaḥ ṭôb yārēk wĕkātēp̄ mālēʾ ʿăṣāmôt mibḥār</em>): <em>Netach tov</em> (good piece/choice cut) — in Ezek 11:3 the city's inhabitants thought they were the <em>basar tov</em> (good meat) protected by the pot. Now YHWH takes up the image: yes, put in the good pieces — but it is the quality of the meat that makes the filth worse. The choicer the contents, the greater the tragedy of the pot's corruption. Jerusalem's privileged covenant status makes her unfaithfulness more, not less, culpable.</p>",
    "5": "<p><strong>mivchar hatson qach vegam daur haatzamot tachateyha rachob rachoba vegam bashel atzameyha betokha</strong> (<em>mibḥar haṣṣōʾn qāḥ wĕgam dûr hāʿăṣāmôt taḥtêhā rabbōt rabbôt wĕgam bašṣēl ʿăṣāmêhā bĕtôkāh</em>): <em>Mivchar hatson</em> (choicest of the flock) — only the best is used. The piling up of bones beneath intensifies the heat. The image of boiling until even the bones soften and dissolve within the pot anticipates the total destruction (v. 10: &#8220;let the bones be burned&#8221;). Nothing protective will remain — the pot will destroy what it contains rather than preserve it.</p>",
    "6": "<p><strong>lachen ko amar Adonai YHWH oi ir hadamim sir asher chelata vo vechelata lo yatza mimenu befeluteha hotsia-uha lo-nafal aleyha goral</strong> (<em>lākēn kōh ʾāmar ʾădōnāy Yhwh ʾôy ʿîr haddāmîm sir ʾăšer ḥelʾātāh bāh wĕḥelʾātāh lōʾ yāṣĕʾāh mimmennāh</em>): <strong>Helah</strong> (חֶלְאָה, rust/scum/filth) is a rare word appearing only in this chapter (vv. 6, 11, 12). It refers to the metallic scum, rust, or crust that forms on bronze pots and cannot be removed even by heat and scrubbing — used here as a metaphor for Jerusalem's indelible moral corruption. <em>Ir hadamim</em> (city of blood) — the combination of indelible filth and blood makes Jerusalem a doubly condemned city: morally corrupt and blood-guilty.</p>",
    "7": "<p><strong>ki dama betokha haya al-tsur hachalaq samatu lo shefachu al-haarets lekhasot aleyhu afar</strong> (<em>kî dāmāh bĕtôkāh hāyāh ʿal-ṣûr heḥālāq śāmāttû lōʾ šĕpāḥûhû ʿal-hāʾāreṣ lĕkassôt ʿālāw ʿāpār</em>): <em>Al-tsur hachalaq</em> (on a bare/smooth rock) — the uncovering of blood is the intensification of guilt. Leviticus 17:13 requires blood from slaughtered animals to be covered with dust; uncovered blood cries out from the ground (Gen 4:10). Jerusalem's blood is exposed on bare rock — it cannot be absorbed, cannot be covered, cannot be silenced. It cries out permanently for judgment.</p>",
    "8": "<p><strong>lehavot chemah lingom niqmah natati et-dama al-tsur hachalaq lebilti hiyasotou</strong> (<em>lĕhaʿălôt ḥēmāh lĕhinqqōm nāqām nātatî ʾet-dāmāh ʿal-ṣûr heḥālāq lĕbiltî hikkāsôt</em>): <em>Lehavot chemah</em> (to stir up fury/wrath) — YHWH deliberately does not cover the blood precisely so that it will generate the wrath required for justice. The exposed blood is not an oversight but a divine choice: uncovered blood will cry until justice answers. The same principle operates in Abel's blood (Gen 4:10), in the martyrs under the altar (Rev 6:9-10) who cry &#8220;how long?&#8221; until the Day of wrath.</p>",
    "9": "<p><strong>lachen ko amar Adonai YHWH oi ir hadamim gam-ani agdil et-hamedura</strong> (<em>lākēn kōh ʾāmar ʾădōnāy Yhwh ʾôy ʿîr haddāmîm gam-ʾănî ʾagdîl ʾet-hamĕdûrâ</em>): The doubled <em>ir hadamim</em> (vv. 6, 9) forms an inclusio around the first portion of the pot-oracle. YHWH now takes the role of cook: &#8220;I also will make the pile of fuel great.&#8221; The judge himself stokes the fire. The divine first-person involvement in the judgment (<em>gam-ani</em>, &#8220;even I&#8221;) signals that this is no ordinary military defeat but YHWH's own judicial action.</p>",
    "10": "<p><strong>harbeh haetsim hadleq haesh hatem habasar veharqach hammizgah vehaetzamot yisarefu</strong> (<em>harbēh hāʿēṣîm hadlēq hāʾēš hatem habbāśār wĕhārqōaḥ hammizgāh wĕhāʿăṣāmôt yiśśārēp̄û</em>): <em>Raqach</em> (רֶקַח, spices/seasoning) — even the spices are added, making the cooking thorough and complete. But the goal is not a meal; it is total consumption. <em>Vehaetzamot yisarefu</em> (let the bones be burned) — the burning of bones is the most complete form of destruction in the ancient world; nothing remains. This is the imagery of 586 BCE enacted in symbol: Jerusalem will be as thoroughly destroyed as a pot boiled until the bones themselves calcify and burn.</p>",
    "11": "<p><strong>veha-amideyha al-gechaleha reqah lema-an yicham venichara nechoshta vetamach betokha tumata visaref chelata</strong> (<em>wĕhāʿĕmîdêhā ʿal-gĕḥālêhā rēqāh lĕmaʿan yiḥam wĕniḥar nĕḥoštāh wĕnittĕkāh bĕtôkāh ṭumʾātāh wĕtiśśārēp̄ ḥelʾātāh</em>): <em>Tumata vesaref chelata</em> (its uncleanness/filthiness melts and its scum is burned) — the double purification: heat to melt the moral filth, fire to burn the scum. The theology of purgative judgment: not destruction for its own sake but the burning-away of what cannot be removed any other way. The pot is set on empty coals — not cooking contents, but burning itself.</p>",
    "12": "<p><strong>leat heluateha tokhlot veloo-yetze mamenna chelata-ha rabbah baesh chelata</strong> (<em>lĕʾōt hĕlʾātāh hôgāʿattāh wĕlōʾ-yēṣēʾ mimmennāh ḥelʾātāh hārabbāh bāʾēš ḥelʾātāh</em>): <em>Heluateha</em> (her toil/wearying) — Jerusalem has worn herself out with &#8220;deception&#8221; or &#8220;lying effort&#8221; (<em>tavlah</em> = falsehood/deception). Despite all the heat and effort, the great scum (<em>chelata harabba</em>) will not come out. The imagery diagnoses the pastoral reality: some corruption is so deep-seated that it cannot be removed by gradual reform — only radical judgment will cleanse it.</p>",
    "13": "<p><strong>betumtekh zimma yaan tiharteykhi velo tahart mitumtekhi lo titaheri od ad haniachi et-chatati vekhi</strong> (<em>bĕṭumʾātēk zimmāh yaʿan ṭihartîk wĕlōʾ ṭāhārt miṭumʾātēk lōʾ tiṭhărî ʿôd ʿad hănîḥî ʾet-ḥēmātî bāk</em>): <em>Betumtekh zimma</em> (in your filthiness/impurity is lewdness) — the filth has become structural; it is not a surface contamination but the substance of the city's identity. <em>Tiharteykhi velo tahart</em> (I tried to cleanse you and you would not be cleansed) — YHWH's prior attempts at purification (prophets, exiles, warnings) were insufficient because the <em>zimmah</em> penetrated too deep. Only the full expenditure of divine wrath (<em>ad haniachi et-chatati</em>) will accomplish what reformers could not.</p>",
    "14": "<p><strong>ani YHWH dibarti baa veasiti lo efra velo achus velo einachem kedrakeyikh ukealeyleikh shafetu otach neum Adonai YHWH</strong> (<em>ʾănî Yhwh dibbartî bāʾāh wĕʿāśîtî lōʾ ʾepraʿ wĕlōʾ-ʾāḥûs wĕlōʾ ʾinnāḥēm kĕdĕrākayik ûkĕʿălîlôtayik šĕpāṭûk nĕʾum ʾădōnāy Yhwh</em>): Three negatives: <em>lo efra</em> (will not relent/let loose), <em>lo achus</em> (will not spare/show pity), <em>lo einachem</em> (will not repent/relent). The triple negative is YHWH's most absolute statement of irrevocable judgment in Ezekiel. The judgment has moved beyond the point of intercession or reversal. Jeremiah had been told similarly not to pray for this people (Jer 7:16; 11:14; 14:11). The divine compassion that normally stays the hand of judgment is here explicitly set aside because the sin has reached its full measure.</p>",
    "15": "<p><strong>vayehi devar-YHWH elai lemor</strong> (<em>wayhî dĕbar-Yhwh ʾēlay lēmōr</em>): The divine-word formula interrupts the cooking-pot oracle to introduce the sign of Ezekiel's wife's death. The structural placement is deliberate: immediately after YHWH's declaration of absolute irrevocable judgment (v. 14), the most personal cost of prophecy is revealed. The prophet who must declare judgment without pity must himself experience loss without public mourning.</p>",
    "16": "<p><strong>ben-adam hineni lokeach mimeykh et-machmad einekha bemaggefa veloh-tispod veloh-tivkeh veloh-tavo dimateykha</strong> (<em>ben-ʾādām hinnênî lōqēaḥ mimmĕkā ʾet-maḥmad ʿênêkā bĕmaggēp̄â wĕlōʾ-tispōd wĕlōʾ-tibkeh wĕlōʾ-tābôʾ dimʿātekā</em>): <strong>Maḥmad ʿênêkā</strong> (מַחְמַד עֵינֶיךָ, delight/desire of your eyes) — the most tender epithet for Ezekiel's wife, occurring nowhere else in this form. The same phrase is applied to the temple in v. 21 (&#8220;the pride of your strength, the desire of your eyes&#8221;), making the wife a type of the temple. Ezekiel's personal loss mirrors Israel's coming loss: as he loses what he most loves, so Israel will lose what she most values. The prophet's body becomes a living prophecy (<em>sign-act</em>).</p>",
    "17": "<p><strong>dom heanek metim avl lo-taase paarcha al-roshekha al-shuv venal-eykha tasse velo tateh el-sefam velechem anashim lo tochel</strong> (<em>dōm hēʾānēq mētîm ʾēbel lōʾ-taʿăśeh pĕʾērĕkā ḥăbōš ʿālêkā wĕnaʿălĕkā taśîm bĕraglêkā wĕlōʾ tate ʾel-śāpām wĕleḥem ʾănāšîm lōʾ tōʾkal</em>): <em>Dom heanek</em> (sigh quietly/groan in silence) — Ezekiel is permitted only suppressed grief, not public mourning. The prohibited mourning rites: not covering the lip (<em>sefam</em> — a sign of lament and uncleanness, Lev 13:45; Mic 3:7), not eating the <em>leḥem anashim</em> (bread of mourners — food brought by community to comfort the bereaved, lit. &#8220;bread of men/condolence food&#8221;). These prohibitions reverse the normal social support for grief, isolating Ezekiel as a sign of the communal devastation to come when Israel will be too overwhelmed to mourn properly.</p>",
    "18": "<p><strong>vadaber el-haam baboker vatamot ishti baarev va-ase baboker ka-asher tsuveti</strong> (<em>wāʾădabbēr ʾel-hāʿam babbōqer wattāmot ʾištî bāʿereb wāʾaʿaś babbōqer kaʾăšer ṣûwwêtî</em>): The verse moves with devastating brevity: &#8220;I spoke to the people in the morning. In the evening my wife died. The next morning I did as I was commanded.&#8221; The emotional compression is itself prophetically significant — the prophet's obedience is total, extending to the most private sphere of his life. There is no gap between divine command and prophetic execution, even when the cost is unbearable.</p>",
    "19": "<p><strong>vayomeru elai haam halo-tagid lanu mah-eleh lanu ki asah khen</strong> (<em>wayyōʾmĕrû ʾēlay hāʿām hăl-ōʾ-taggîd lānû mah-ʾēlleh lānû kî ʿōśeh kōhen</em>): The people's question (<em>mah-eleh lanu</em>, &#8220;what do these things mean for us?&#8221;) is precisely what sign-acts are designed to provoke. The community understands that Ezekiel's unusual behavior is a communicative act — a <em>mofet</em> (sign) — and seeks the interpretation. This is the hermeneutical function of prophetic embodiment: to create curiosity and readiness for the word of interpretation.</p>",
    "20": "<p><strong>vaomar alayhem dvar-YHWH hayah elai lemor</strong> (<em>wāʾōmar ʾălêhem dĕbar-Yhwh hāyāh ʾēlay lēmōr</em>): The divine-word reception formula is Ezekiel's standard authorization marker. The insertion of this formula in the midst of the narrative (between the question and the answer) emphasizes that what follows is not Ezekiel's personal explanation but a divinely authorized interpretation. The prophet is not performing a creative act of self-expression; he is transmitting the meaning YHWH attached to the sign.</p>",
    "21": "<p><strong>emor leveit Yisrael ko amar Adonai YHWH hineni mechalel et-miqdashi geyon uzekhem machmad einekhem umachmad naphsheykhem uvneyikhem uvnoteyikhem asher azavtem bacherev yipolu</strong> (<em>ʾĕmōr lĕbêt yiśrāʾēl kōh ʾāmar ʾădōnāy Yhwh hinnênî mĕḥallēl ʾet-miqdāšî gĕʾôn ʿuzzĕkem maḥmad ʿênêkem</em>): <em>Geyon uzekhem</em> (the pride of your strength) — the temple is Jerusalem's identity-anchor: the source of national pride, the guarantee of divine protection. <em>Machmad einekhem umachmad naphsheykhem</em> (the desire of your eyes, the longing of your souls) — the same word used for Ezekiel's wife (v. 16). YHWH will profane his own sanctuary as the most devastating possible act: taking what Israel valued most as YHWH's own possession and subjecting it to destruction.</p>",
    "22": "<p><strong>vasitem et asher asiti el-sefam lo tachpehu velechem anashim lo tochelu</strong> (<em>waʿăśîtem kĕʾăšer ʿāśîtî ʾel-śāpām lōʾ tĕḥāp̄û wĕleḥem ʾănāšîm lōʾ tōʾkēlû</em>): Israel will do what Ezekiel did (no covering the lip, no eating mourner's bread) — not because they are commanded to, but because the scale of disaster will be beyond normal mourning. The prophet's sign-act anticipates a national paralysis of grief: too many dead, too rapid a collapse, too overwhelming a loss for the normal ritual of mourning to contain.</p>",
    "23": "<p><strong>ufearekhem al-roshekhem venaaleykhem beragleykhem lo tispadu velo tivku unemastem baavonoteykhem venehamtem ish el-achiv</strong> (<em>ûp̄iʾarêkem ʿal-rāʾšêkem wĕnaʿălêkem bĕraglêkem lōʾ tispĕdû wĕlōʾ tibkû ûnĕmaqqôtem baʿăwōnōtêkem wĕnĕhāmtem ʾîš ʾel-ʾāḥîw</em>): <em>Unemastem baavonoteykhem</em> (you will waste away/rot in your iniquities) — the verb <em>maqaq</em> (to melt, rot, waste away) is used elsewhere for physical decay (Isa 34:4; Zech 14:12). Here it is the spiritual and communal rotting that comes not from the disaster itself but from the accumulated iniquity that generated it. The mourning that cannot be publicly enacted will be processed privately in the recognition of deserved judgment.</p>",
    "24": "<p><strong>veEzekiel lahem lemofet kekol asher asa taasuun behavo tideu ki ani Adonai YHWH</strong> (<em>wĕyĕḥezqēʾl lākem lĕmôp̄ēt kĕkōl ʾăšer-ʿāśāh taʿăśûn bĕbōʾô tēdĕʿû kî ʾănî ʾădōnāy Yhwh</em>): <strong>Mofet</strong> (מוֹפֵת, sign/wonder/portent) — the same word used for the miraculous signs of the Exodus (Deut 4:34; 6:22; 7:19). Ezekiel is himself a sign of the caliber of the Exodus signs: his life enacts prophetically what YHWH is about to do nationally. The recognition formula (<em>tideu ki ani Adonai YHWH</em>) is the climax: when the disaster matches the sign, Israel will know who YHWH truly is.</p>",
    "25": "<p><strong>veata ben-adam halo beyom kekhti meyhem et-mazuzam gaon ezam machmad eineyhem umasha naphsham et-beneyhem veet-benoteyhem</strong> (<em>wĕʾattāh ben-ʾādām hălōʾ bĕyôm qeḥtî mēhem ʾet-mĕʿûzzām śimḥat tip̄ʾartām maḥmad ʿênêhem ûmašʾat naphšām bĕnêhem ûbĕnôtêhem</em>): The accumulation of terms for what Israel valued most — <em>mazon ezam</em> (their stronghold), <em>simchat tifartam</em> (the joy of their glory), <em>machmad eineyhem</em> (the desire of their eyes), <em>mashat naphsham</em> (the longing of their soul) — and then &#8220;their sons and daughters&#8221; — piles up what will be taken. The temple, the children: everything. The day of maximum loss is the day that will finally produce true recognition of YHWH.</p>",
    "26": "<p><strong>beyom hahu yavo eleyha hapaleit lehashmia etneyikh</strong> (<em>bĕyôm hahûʾ yābōʾ ʾēlêhā happālîṭ lĕhašmîaʿ ʾoznêkā</em>): <em>Hapaleit</em> (the fugitive/escapee) — this is the escapee who brings news (cf. Ezek 33:21 where the fugitive arrives). The coming of the fugitive signals the end of Ezekiel's prophetic dumbness (v. 27). The structural function: the prophet's silence corresponds to the silence of God's patience; when judgment falls and the fugitive arrives, both the prophet and the message are released.</p>",
    "27": "<p><strong>beyom hahu yipatach piykha et-hapaleit vetidaber velo teaelem od vehayita lahem lemofet vedau ki ani YHWH</strong> (<em>bĕyôm hahûʾ yippātaḥ pîkā ʾet-hāpālîṭ wĕdibbartā wĕlōʾ tēʾālēm ʿôd wĕhāyîtā lāhem lĕmôp̄ēt wĕyādĕʿû kî ʾănî Yhwh</em>): <em>Yipatach piykha</em> (your mouth will be opened) — Ezekiel has been dumb/restricted in speech since 3:26 (&#8220;I will make your tongue cling to the roof of your mouth&#8221;). This verse announces the end of that restriction when the news of Jerusalem's fall arrives. The prophet's muteness mirrored the silence of divine patience; the opening of his mouth will mirror the outpouring of YHWH's restorative speech in chs. 33-48. The entire prophetic program pivots on this verse.</p>"
  },
  "25": {
    "1": "<p><strong>vayehi devar-YHWH elai lemor</strong> (<em>wayhî dĕbar-Yhwh ʾēlay lēmōr</em>): Chapters 25-32 constitute Ezekiel's oracles against foreign nations (<em>oracles against the nations</em>), a standard section in major prophetic books (Isa 13-23; Jer 46-51; Amos 1-2). Ezekiel's foreign-nation oracles are structurally positioned between the fall-of-Jerusalem oracles (chs. 1-24) and the restoration oracles (chs. 33-48), forming a central bridge: the nations that gloated over Israel's fall will themselves fall, and Israel's restoration will occur in their wake. Chapter 25 covers the four closest neighbors: Ammon, Moab, Edom, and Philistia.</p>",
    "2": "<p><strong>ben-adam sim panekha el-bney ammon vehinnave alayhem</strong> (<em>ben-ʾādām śîm pānêkā ʾel-bĕnê ʿammôn wĕhinnābēʾ ʾălêhem</em>): <em>Sim panekha el</em> (set your face toward) — the prophetic posture of confrontational address. The same formula introduces oracles against Israel (Ezek 6:2; 13:17) and foreign nations (29:2; 35:2). The physical orientation of the prophet's face is the visible embodiment of divine attention turning toward judgment. Ammon (modern Jordan, east of the Jordan River) was a persistent enemy of Israel from the judges period through the post-exilic era.</p>",
    "3": "<p><strong>veamarta livney ammon shimau dvar Adonai YHWH ko amar Adonai YHWH yaan amarekh heach el-miqdashi ki nihal veal-admat Yisrael ki nishama veal-beit Yehudah ki halchu bagolah</strong> (<em>wĕʾāmartā lĭbnê ʿammôn šimʿû dĕbar-ʾădōnāy Yhwh kōh ʾāmar ʾădōnāy Yhwh yaʿan ʾomrekem heʾāḥ ʾel-miqdāšî kî niḥāl</em>): <em>Heach!</em> — the exclamation of malicious glee at another's misfortune, cognate to the German <em>Schadenfreude</em>. Three objects of Ammon's gleeful contempt: (1) YHWH's sanctuary when profaned; (2) the land of Israel when desolated; (3) the house of Judah when exiled. The tripling intensifies the charge: their joy was total, covering every dimension of Israel's catastrophe. Rejoicing over Israel's disaster is treated as an attack on YHWH himself — to mock the sanctuary is to mock the one who dwells there.</p>",
    "4": "<p><strong>lachen hineni notencha livney-qedem lemorah vehotsivu tiroteyhem bekhekh veshamu mishkenoteyhem bekhekh hemah yochelu piryekh veimah yishtu chalvekh</strong> (<em>lākēn hinnênî nōtēnĕkā lĭbnê-qedem lĕmôrāšâ wĕyōšĕbû ṭîrôtêhem bāk wĕnātĕnû mišĕkĕnôtêhem bāk hēmmāh yōʾklû piryēk wĕhēmmāh yišĕtû ḥalbēk</em>): <em>Bney-qedem</em> (sons/people of the East) — nomadic desert peoples (cf. Gen 29:1; Judg 6:3; Job 1:3). Ammon's land will become the possession of the very people who lived at Ammon's margins. The judgment is fitting: Ammon rejoiced over others losing their land; now Ammon loses its own. <em>Tiroteyhem... mishkenoteyhem</em> (encampments... dwellings) — the nomads will settle permanently in what was Ammon's territory.</p>",
    "5": "<p><strong>venatati et-Rabbah lingveh gemalim veet-beny ammon lemeratch tson vidaatem ki ani YHWH</strong> (<em>wĕnātatî ʾet-rabbāh lĭnwēh gĕmallîm wĕʾet-bĕnê ʿammôn lĕmirbaṣ ṣōʾn ûyĕdaʿtem kî ʾănî Yhwh</em>): <strong>Rabbah</strong> (רַבָּה, modern Amman, Jordan) was Ammon's capital city, one of the most important cities in the Transjordan region. Its reduction to a <em>neveh gemalim</em> (pasture for camels) is the maximally degrading fate for an urban capital: from royal city to grazing ground. The recognition formula (<em>vidaatem ki ani YHWH</em>) attached to the judgment of a foreign nation is significant: even pagan nations will come to know YHWH through his judgments on Israel's enemies.</p>",
    "6": "<p><strong>ki ko amar Adonai YHWH yaan meqekh kaf verakha regel vetismach bekol-sheat naphsheykha el-admat Yisrael</strong> (<em>kî kōh ʾāmar ʾădōnāy Yhwh yaʿan meqekem kap̄ wĕrāqoʿa regel wĕtišmĕḥû bĕkol-šeʾat naphšĕkā ʾel-ʾadmat yiśrāʾēl</em>): <em>Meqekh kaf</em> (clapping hands) and <em>raqoa regel</em> (stamping feet) — these are the physical expressions of contemptuous schadenfreude at Israel's destruction. The language implies a kind of victory dance: Ammon celebrated Israel's exile. The charge reinforces v. 3: Ammon's sin is not merely passive indifference but active, gleeful celebration of a covenant-neighbor's disaster.</p>",
    "7": "<p><strong>lachen hineni natiti et-yadi alaykha untatikha levaz lagoyim vekhiratiykha min-haammim vehavdatiykha min-haaratsot veishmidtiykha vidaata ki ani YHWH</strong> (<em>lākēn hinnênî nāṭîtî ʾet-yādî ʿālêkā ûnĕtattîkā lĕbaz laggôyim wĕkārattîkā min-hāʿammîm wĕhāʾabadtîkā min-hāʾărāṣôt wĕhišmadtîkā wĕyādaʿtā kî ʾănî Yhwh</em>): <em>Natiti et-yadi alaykha</em> (I stretched out my hand against you) — the formula of divine judgment-action (cf. 6:14; 14:9; 16:27). The five verbs of judgment (give as plunder, cut off, destroy from lands, annihilate) cascade in total devastation. Importantly the recognition formula (<em>vidaata ki ani YHWH</em>, &#8220;you will know that I am the LORD&#8221;) is second-person singular, addressed to Ammon: Ammon will come to know YHWH through judgment on itself.</p>",
    "8": "<p><strong>ko amar Adonai YHWH yaan amor Moav useir hineh keveit Yisrael kekol hagoyim</strong> (<em>kōh ʾāmar ʾădōnāy Yhwh yaʿan ʾemar mōʾāb wĕśēʿîr hinnēh kĕbêt yiśrāʾēl kĕkol-haggôyim</em>): <em>Hineh keveit Yisrael kekol-hagoyim</em> (&#8220;the house of Judah is like all the other nations&#8221;) — this is the insult that triggers Moab's judgment: the theological claim that Israel/Judah has no special covenantal status, that YHWH's election of Israel is void or never existed. This is the deepest possible attack on the covenant relationship. To say Israel is &#8220;like all the nations&#8221; is to deny YHWH's choice, YHWH's faithfulness, and YHWH's capacity to maintain a covenant people. The insult is against YHWH as much as against Israel.</p>",
    "9": "<p><strong>lachen hineni potach et-keter Moav meheaarim meaareiv miaqtsar tifarto Beit HaYeshimot Baal Meon vKiriyataim</strong> (<em>lākēn hinnênî p̄ōtēaḥ ʾet-kĕtep̄ mōʾāb mēhʿārîm mēʿārāyw miqqĕṣēhû tĕp̄ʾartô bêt hayyĕšimōt bĕʿal mĕʿôn wĕqiryātāyim</em>): <em>Keter Moav</em> (the flank/shoulder of Moab) — the strategic frontier region. <strong>Beth-jeshimoth</strong> (house of the desolations), <strong>Baal-meon</strong> (lord of habitation), and <strong>Kiriathaim</strong> (double city) were the glory-cities of Moab's northern border — their capture would be the beginning of the end for Moab's territorial integrity. The divine opening of Moab's flank is the tactical precision of YHWH as military strategist against Israel's enemies.</p>",
    "10": "<p><strong>livney qedem al-bney ammon unetatiyah lemorah lema-an lo-tizaker bney ammon bagoyim</strong> (<em>lĭbnê qedem ʿal-bĕnê ʿammôn ûnĕtattîhā lĕmôrāšâ lĕmaʿan lōʾ-tizzāḵēr bĕnê ʿammôn baggôyim</em>): Both Ammon and Moab receive the same judgment of being given to the &#8220;sons of the East.&#8221; The double judgment creates structural symmetry: two nations that insulted Israel (Ammon gleefully, Moab theologically) receive the same fate. <em>Lema-an lo-tizaker</em> (so that Ammon may not be remembered among the nations) — obliteration of national memory is the ultimate judgment for a nation: not merely defeat but total erasure from the historical record.</p>",
    "11": "<p><strong>uvemoav esa shefatim videu ki ani YHWH</strong> (<em>ûbĕmōʾāb ʾeʿśeh šĕp̄āṭîm wĕyādĕʿû kî ʾănî Yhwh</em>): <em>Esa shefatim</em> (I will execute judgments) — the plural <em>shefatim</em> emphasizes the comprehensive and multiple nature of YHWH's judgment on Moab. The recognition formula is again applied to a pagan nation: the purpose of judgment is always ultimately knowledge of YHWH. Even through the destruction of Israel's enemies, YHWH's identity and character are being disclosed.</p>",
    "12": "<p><strong>ko amar Adonai YHWH yaan asot Edom benakom levet Yehudah vayishmu asham vayinqemu bahem</strong> (<em>kōh ʾāmar ʾădōnāy Yhwh yaʿan ʿăśôt ʾĕdôm bĕnāqōm lĕbêt yĕhûdāh wayyaʾšĕmû ʾāšôm wayyinqĕmû bāhem</em>): <em>Edom benaqom</em> (Edom in taking vengeance) — Edom's sin is specifically named as <em>naqqam</em> (vengeance), amplified by <em>vayashmu asham</em> (incurred great guilt). Edom was Israel's brotherly enemy — descended from Esau — and their betrayal of Judah during the Babylonian siege (Ps 137:7; Obad 10-14; Lam 4:21-22) was particularly bitter. Of all the nations judged in ch. 25, Edom receives the most extensive treatment in Ezekiel (cf. ch. 35) because the brotherly betrayal is theologically more significant than the foreign nations' hostility.</p>",
    "13": "<p><strong>lachen ko amar Adonai YHWH venatatiy et-yadi el-Edom vehikhratiy mimenu adam uvehemah vanatatihu leshomamah miteyman uvdedanim becharev yipolu</strong> (<em>lākēn kōh ʾāmar ʾădōnāy Yhwh ûnātatî ʾet-yādî ʾel-ʾĕdôm wĕhikrattî mimmennû ʾādām ûbĕhēmāh wĕnĕtattîhû lĕšāmemāh mîtêmān ûdĕdānāh baḥereb yippōlû</em>): <em>Teman</em> (תֵּימָן, south/right-hand direction) was a region/city in northern Edom known for wisdom (Jer 49:7; Obad 9). <em>Dedan</em> was in the south. The desolation &#8220;from Teman&#8221; to those of &#8220;Dedan&#8221; covers Edom's entire north-to-south extent — comprehensive territorial destruction. The combination of human and animal death (<em>adam uvehemah</em>) is the total desolation formula (cf. Jer 7:20; 21:6), indicating the land itself becomes uninhabitable.</p>",
    "14": "<p><strong>venatati et-niqmati beEdom beyad ami Yisrael veasu veEdom keapyi ukhemati veyadeu et-niqmati neum Adonai YHWH</strong> (<em>wĕnātatî ʾet-niqmātî bĕʾĕdôm bĕyad ʿammî yiśrāʾēl wĕʿāśû bĕʾĕdôm kĕʾappî ûkăḥēmātî wĕyādĕʿû ʾet-niqmātî nĕʾum ʾădōnāy Yhwh</em>): <em>Niqmati</em> (my vengeance) — YHWH personally executes vengeance on Edom. Uniquely here, the instrument is &#8220;my people Israel&#8221; — not the nations of the East or Babylonian armies. This anticipates the Obadiah and Malachi oracles about Edom's final fate. The recognition formula is formulated differently: not &#8220;they will know that I am the LORD&#8221; but &#8220;they will know my vengeance&#8221; — they will know YHWH through the experience of his retributive justice.</p>",
    "15": "<p><strong>ko amar Adonai YHWH yaan asot Pelishtim beneqamah veyinqemu besha nefarsh vishammi leashmidam beyivat olam</strong> (<em>kōh ʾāmar ʾădōnāy Yhwh yaʿan ʿăśôt pĕlištîm bĕnĕqāmāh ûnaqqĕmû bĕšāʾṭ nĕp̄ereš wĕyašḥîtû bĕʾēbat ʿôlām lĕmašĕḥît</em>): <strong>Eyvah ʿôlam</strong> (אֵיבַת עוֹלָם, ancient/eternal enmity) — the Philistine hostility toward Israel is characterized as a permanent, unrelenting hatred rooted in antiquity. The Philistines are the paradigmatic enemy of Israel from the judges period through David's wars. <em>Bisha nefresh</em> (with malice/contempt of soul) — the Philistine revenge had a specifically psychological viciousness, not merely political opportunism. This ancient enmity is what the oracle holds them accountable for.</p>",
    "16": "<p><strong>lachen ko amar Adonai YHWH hineni noteh yadi el-Pelishtim vehikhratiy et-Keretim vehiabadeti et-sherith hof hayam</strong> (<em>lākēn kōh ʾāmar ʾădōnāy Yhwh hinnênî nōṭeh yādî ʿal-pĕlištîm wĕhikrattî ʾet-kĕrētîm wĕhāʾabadtî ʾet-šĕʾērît ḥôp̄ hayyām</em>): <em>Keretim</em> (כְּרֵתִים, Cherethites) — a Philistine sub-group, often identified with Cretans (LXX reads &#8220;Cretans&#8221;; 1 Sam 30:14; 2 Sam 8:18). The Cherethites were among David's elite royal guard (2 Sam 8:18; 1 Kings 1:38) — a remarkable use of Philistine mercenaries in Israel's service. <em>Sherit hof hayam</em> (remnant of the seacoast) — the Philistine coastal strip (Gaza, Ashkelon, Ashdod, Ekron, Gath) defined by its Mediterranean coastline. The seacoast that had been Philistia's geographic advantage is named as the boundary of its destruction.</p>",
    "17": "<p><strong>veasiti vahem neqamot gedolot betochechet chemah veydeu ki ani YHWH benatati et-niqmati bahem</strong> (<em>wĕʿāśîtî bāhem nĕqāmôt gĕdōlôt bĕtôkĕḥôt ḥēmāh wĕyādĕʿû kî ʾănî Yhwh bĕnitî ʾet-niqmātî bāhem</em>): <em>Neqamot gedolot betochechet chemah</em> (great vengeance with wrathful rebukes) — the closing formula of the four-nation oracle section escalates to &#8220;great vengeance&#8221; against the Philistines, as though YHWH's judgment intensifies with each nation named. The final recognition formula — &#8220;they will know that I am the LORD when I lay my vengeance upon them&#8221; — frames the entire chapter 25 oracle unit: every judgment against every nation ultimately serves the disclosure of YHWH's identity as the sovereign LORD who keeps covenant-justice for his people.</p>"
  }
}

def main():
    c = load_comm("original", "ezekiel")
    merge_comm(c, EZEKIEL_ORIGINAL)
    save_comm("original", "ezekiel", c)
    for ch in ["23", "24", "25"]:
        vv = c.get(ch, {})
        print(f"  ch{ch}: {len(vv)} verse(s) with original commentary")

if __name__ == "__main__":
    main()
